Since the entries do not store the position (only the hash) probably the best you can do is traversing the reachable nodes. So something like this:

```
import chess
import chess.polyglot

def traverse(book, d, board):
    epd = board.epd()

    if not epd in d:
        try:
            move = book.find(board).move()
        except IndexError:
            pass
        else:
            print(epd, move)
            d[epd] = move

            for move in board.legal_moves:
                board.push(move)
                traverse(book, d, board)
                board.pop()

book = chess.polyglot.open_reader("data/polyglot/performance.bin")
fen_to_best_move = {}
traverse(book, fen_to_best_move, chess.Board())
```

